			parts.preamble = bytes.Trim(src[:lineStart], "\n")
			parts.imports, parts.rest = extractImportSection(src[lineStart:])
			parts.rest = bytes.TrimLeft(parts.rest, "\n")
			return parts
		}
	}

	parts.rest = bytes.Trim(src, "\n")
	return parts
