func extractImportSection(src []byte) (imports, rest []byte) {
	offset := 0
	firstImportStart := -1
	lastImportEnd := 0

	for {
		candidateStart := offset
		significantStart, lineEnd, ok := nextSignificantLine(src, offset)
		if !ok {
