		lineEnd = offset
		if offset < len(src) && src[offset] == '\n' {
			offset++
		}

		line := bytes.TrimSpace(src[lineStart:lineEnd])
		if inBlockComment {
			if bytes.Contains(line, []byte("*/")) {
				inBlockComment = false
			}
			continue
		}
		switch {
		case len(line) == 0:
			continue
		case bytes.HasPrefix(line, []byte("//")):
			continue
		case bytes.HasPrefix(line, []byte("/*")):
			if !bytes.Contains(line, []byte("*/")) {
				inBlockComment = true
			}
			continue
		default:
			return lineStart, lineEnd, true
		}
	}
	return 0, 0, false
