				if quote != '`' && line[i] == '\\' && i+1 < len(line) {
					i++
					continue
				}
				if line[i] == quote {
					break
				}
			}
		}
	}
	return delta, hasParen, nextInBlockComment
}

func joinGeneratedSections(parts ...[]byte) []byte {
	trimmed := make([][]byte, 0, len(parts))
	for _, part := range parts {
		part = bytes.Trim(part, "\n")
		if len(part) == 0 {
