func nextSignificantLine(src []byte, offset int) (lineStart, lineEnd int, ok bool) {
	inBlockComment := false
	for offset < len(src) {
		lineStart = offset
		for offset < len(src) && src[offset] != '\n' {
			offset++
		}
		lineEnd = offset
		if offset < len(src) && src[offset] == '\n' {
			offset++
		}

		line := bytes.TrimSpace(src[lineStart:lineEnd])
		if inBlockComment {
			if bytes.Contains(line, []byte("*/")) {
				inBlockComment = false
			}
			continue
		}
		switch {
		case len(line) == 0:
			continue
		case bytes.HasPrefix(line, []byte("//")):
			continue
		case bytes.HasPrefix(line, []byte("/*")):
			if !bytes.Contains(line, []byte("*/")) {
				inBlockComment = true
			}
			continue
		default:
			return lineStart, lineEnd, true
		}
	}
	return 0, 0, false
}

func consumeImportDecl(src []byte, start int) int {
	depth := 0
	seenParen := false
	inBlockComment := false
	offset := start
	for offset < len(src) {
		lineStart := offset
		for offset < len(src) && src[offset] != '\n' {
			offset++
		}
		lineEnd := offset
		if offset < len(src) && src[offset] == '\n' {
			offset++
		}
		line := src[lineStart:lineEnd]
		delta, hasParen, nextInBlockComment := importParenDelta(line, inBlockComment)
		depth += delta
		inBlockComment = nextInBlockComment
		if hasParen {
			seenParen = true
		}
		if !seenParen || depth <= 0 {
			return offset
		}
	}
	return len(src)
}

func importParenDelta(line []byte, inBlockComment bool) (delta int, hasParen bool, nextInBlockComment bool) {
	nextInBlockComment = inBlockComment
	for i := 0; i < len(line); i++ {
		if nextInBlockComment {
			if i+1 < len(line) && line[i] == '*' && line[i+1] == '/' {
				nextInBlockComment = false
				i++
			}
			continue
		}

		if i+1 < len(line) {
			switch {
			case line[i] == '/' && line[i+1] == '/':
				return delta, hasParen, nextInBlockComment
			case line[i] == '/' && line[i+1] == '*':
				nextInBlockComment = true
				i++
